    public Object parseTickers(Object tickers, Object... optionalArgs)
    {
        Object symbols = Helpers.getArg(optionalArgs, 0, null);
        Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
        Object result = new java.util.HashMap<String, Object>() {{}};
        Object keys = Helpers.objectKeys(tickers);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(keys)); i++)
        {
            Object key = Helpers.GetValue(keys, i);
            Object ticker = Helpers.GetValue(tickers, key);
            Object marketId = this.safeString(ticker, "symbol", key);
            Object market = this.safeMarket(marketId, null, "-");
            Object symbol = Helpers.GetValue(market, "symbol");
            Helpers.addElementToObject(result, symbol, this.extend(this.parseTicker(ticker, market), parameters));
        }
        return this.filterByArrayTickers(result, "symbol", symbols);
    }

    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        // fetchTicker
        //
        //     {
        //         "open": 8615.55,
        //         "close": 8841.05,
        //         "high": 8921.1,
        //         "low": 8607,
        //         "last": 8841.05,
        //         "volume": 20.2802,
        //         "timestamp": "2020-03-03T03:11:18.964Z",
        //     }
        //
        // fetchTickers
        //
        //     {
        //         "time": "2020-03-02T04:29:45.011Z",
        //         "open": 341.65,
        //         "close": 337.9,
        //         "high": 341.65,
        //         "low": 337.3,
        //         "last": 337.9,
        //         "volume": 0.054,
        //         "symbol": "bch-usdt"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(ticker, "symbol");
        market = this.safeMarket(marketId, market, "-");
        Object symbol = Helpers.GetValue(market, "symbol");
        Object timestamp = this.parse8601(this.safeString2(ticker, "time", "timestamp"));
        Object close = this.safeString(ticker, "close");
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "info", ticker );
            put( "timestamp", timestamp );
            put( "datetime", HollaexCore.this.iso8601(timestamp) );
            put( "high", HollaexCore.this.safeString(ticker, "high") );
            put( "low", HollaexCore.this.safeString(ticker, "low") );
            put( "bid", null );
            put( "bidVolume", null );
            put( "ask", null );
            put( "askVolume", null );
            put( "vwap", null );
            put( "open", HollaexCore.this.safeString(ticker, "open") );
            put( "close", close );
            put( "last", HollaexCore.this.safeString(ticker, "last", close) );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", null );
            put( "average", null );
            put( "baseVolume", HollaexCore.this.safeString(ticker, "volume") );
            put( "quoteVolume", null );
        }}, market);
    }

