    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades (public)
        //
        //     {
        //         "size": 0.5,
        //         "price": 8830,
        //         "side": "buy",
        //         "timestamp": "2020-03-03T04:44:33.034Z"
        //     }
        //
        // fetchMyTrades (private)
        //  {
        //      "side":"sell",
        //      "symbol":"doge-usdt",
        //      "size":70,
        //      "price":0.147411,
        //      "timestamp":"2022-01-26T17:53:34.650Z",
        //      "order_id":"cba78ecb-4187-4da2-9d2f-c259aa693b5a",
        //      "fee":0.01031877,
        //      "fee_coin":"usdt"
        //  }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(trade, "symbol");
        market = this.safeMarket(marketId, market, "-");
        Object symbol = Helpers.GetValue(market, "symbol");
        Object datetime = this.safeString(trade, "timestamp");
        Object timestamp = this.parse8601(datetime);
        Object side = this.safeString(trade, "side");
        Object orderId = this.safeString(trade, "order_id");
        Object priceString = this.safeString(trade, "price");
        Object amountString = this.safeString(trade, "size");
        Object feeCostString = this.safeString(trade, "fee");
        Object feeCoin = this.safeString(trade, "fee_coin");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeCostString, null)))
        {
            final Object finalFeeCostString = feeCostString;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCostString );
                put( "currency", HollaexCore.this.safeCurrencyCode(feeCoin) );
            }};
        }
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", null );
            put( "timestamp", timestamp );
            put( "datetime", datetime );
            put( "symbol", symbol );
            put( "order", orderId );
            put( "type", null );
            put( "side", side );
            put( "takerOrMaker", null );
            put( "price", priceString );
            put( "amount", amountString );
            put( "cost", null );
            put( "fee", finalFee );
        }}, market);
    }

