    public Object parseOrderStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "new", "open" );
            put( "pfilled", "open" );
            put( "filled", "closed" );
            put( "canceled", "canceled" );
        }};
        return this.safeString(statuses, ((String)status), status);
    }

    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        // createOrder, fetchOpenOrder, fetchOpenOrders
        //
        //     {
        //          "id":"10644b7e-3c90-4ba9-bc3b-188f3a4e9cfd",
        //          "created_by":140093,
        //          "exchange_id":22,
        //          "side":"buy",
        //          "symbol":"doge-usdt",
        //          "type":"limit",
        //          "price":0.05,
        //          "size":10,
        //          "stop":null,
        //          "filled":0,
        //          "status":"canceled",
        //          "fee":0,
        //          "fee_coin":"doge",
        //          "meta": {                 // optional field only returned for postOnly orders
        //              "post_only":true
        //          },
        //          "fee_structure": {
        //              "maker":0.1,
        //              "taker":0.1
        //          },
        //          "created_at":"2022-05-31T08:14:14.747Z",
        //          "updated_at":"2022-05-31T08:14:23.727Z"
        //      }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(order, "symbol");
        Object symbol = this.safeSymbol(marketId, market, "-");
        Object id = this.safeString(order, "id");
        Object timestamp = this.parse8601(this.safeString(order, "created_at"));
        Object type = this.safeString(order, "type");
        Object side = this.safeString(order, "side");
        Object price = this.safeString(order, "price");
        Object amount = this.safeString(order, "size");
        Object filled = this.safeString(order, "filled");
        Object status = this.parseOrderStatus(this.safeString(order, "status"));
        Object meta = this.safeValue(order, "meta", new java.util.HashMap<String, Object>() {{}});
        Object postOnly = this.safeBool(meta, "post_only", false);
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "clientOrderId", null );
            put( "timestamp", timestamp );
            put( "datetime", HollaexCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "status", status );
            put( "symbol", symbol );
            put( "type", type );
            put( "timeInForce", null );
            put( "postOnly", postOnly );
            put( "side", side );
            put( "price", price );
            put( "triggerPrice", HollaexCore.this.safeString(order, "stop") );
            put( "amount", amount );
            put( "filled", filled );
            put( "remaining", null );
            put( "cost", null );
            put( "trades", null );
            put( "fee", null );
            put( "info", order );
            put( "average", null );
        }}, market);
    }

    /**
     * @method
     * @name hollaex#createOrder
     * @description create a trade order
     * @see https://apidocs.hollaex.com/#create-order
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {string} type 'market' or 'limit'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount how much of currency you want to trade in units of base currency
     * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {float} [params.triggerPrice] the price at which a trigger order is triggered at
     * @param {bool} [params.postOnly] if true, the order will only be posted to the order book and not executed immediately
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrder(Object symbol, Object type2, Object side, Object amount, Object... optionalArgs)
    {
        final Object type3 = type2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object type = type3;
            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            final Object finalType = type;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "side", side );
                put( "size", HollaexCore.this.amountToPrecision(symbol, amount) );
                put( "type", finalType );
            }};
            Object triggerPrice = this.safeNumberN(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("triggerPrice", "stopPrice", "stop")));
            Object meta = this.safeValue(parameters, "meta", new java.util.HashMap<String, Object>() {{}});
            Object exchangeSpecificParam = this.safeBool(meta, "post_only", false);
            Object isMarketOrder = Helpers.isEqual(type, "market");
            Object postOnly = this.isPostOnly(isMarketOrder, exchangeSpecificParam, parameters);
            if (!Helpers.isTrue(isMarketOrder))
            {
                Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
            }
            if (Helpers.isTrue(!Helpers.isEqual(triggerPrice, null)))
            {
                Helpers.addElementToObject(request, "stop", this.priceToPrecision(symbol, triggerPrice));
            }
            if (Helpers.isTrue(postOnly))
            {
                Helpers.addElementToObject(request, "meta", new java.util.HashMap<String, Object>() {{
        put( "post_only", true );
    }});
            }
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("postOnly", "timeInForce", "stopPrice", "triggerPrice", "stop")));
            Object response = (this.privatePostOrder(this.extend(request, parameters))).join();
            //
            //     {
            //         "fee": 0,
            //         "meta": {},
            //         "symbol": "xht-usdt",
            //         "side": "sell",
            //         "size": 0.1,
            //         "type": "limit",
            //         "price": 1,
            //         "fee_structure": {
            //             "maker": 0.2,
            //             "taker": 0.2
            //         },
            //         "fee_coin": "usdt",
            //         "id": "string",
            //         "created_by": 116,
            //         "filled": 0,
            //         "status": "new",
            //         "updated_at": "2021-02-17T03:03:19.231Z",
            //         "created_at": "2021-02-17T03:03:19.231Z",
            //         "stop": null
            //     }
            //
            return this.parseOrder(response, market);
        });

    }

